1	/**
2	 * SQLite backend for The Stacks — backed by better-sqlite3.
3	 *
4	 * Implements the StacksBackend interface. All SQLite-specific details
5	 * (json_extract, table naming, WAL mode) are encapsulated here.
6	 *
7	 * Documents are stored as JSON blobs in a `content` TEXT column.
8	 * Field queries use json_extract() against declared indexes.
9	 */
10	
11	import path from 'node:path';
12	import Database from 'better-sqlite3';
13	import type { Database as DB } from 'better-sqlite3';
14	
15	import type {
16	  BackendOptions,
17	  BackendTransaction,
18	  BookRef,
19	  CountQuery,
20	  DeleteResult,
21	  InternalCondition,
22	  InternalQuery,
23	  PatchResult,
24	  PutResult,
25	  StacksBackend,
26	} from './backend.ts';
27	import type { BookEntry, BookSchema } from './types.ts';
28	import { validateFieldName } from './query.ts';
29	
30	// ── Table naming ──────────────────────────────────────────────────────
31	
32	const SAFE_BOOK_NAME_RE = /^[A-Za-z0-9_-]+$/;
33	
34	function normalizeOwnerId(ownerId: string): string {
35	  return ownerId.replace(/\//g, '__').replace(/[^a-z0-9_]/g, '_');
36	}
37	
38	export function tableName(ref: BookRef): string {
39	  if (!SAFE_BOOK_NAME_RE.test(ref.book)) {
40	    throw new Error(`[stacks/sqlite] Unsafe book name rejected: "${ref.book}"`);
41	  }
42	  return `books_${normalizeOwnerId(ref.ownerId)}_${ref.book}`;
43	}
44	
45	// ── JSON path helpers ─────────────────────────────────────────────────
46	
47	function toJsonPath(field: string): string {
48	  return '$.' + validateFieldName(field);
49	}
50	
51	function jsonExtract(field: string): string {
52	  return `json_extract(content, '${toJsonPath(field)}')`;
53	}
54	
55	// ── Query builder ─────────────────────────────────────────────────────
56	
57	interface SqlParts {
58	  sql: string;
59	  args: unknown[];
60	}
61	
62	function buildWhere(conditions?: InternalCondition[]): SqlParts {
63	  if (!conditions || conditions.length === 0) {
64	    return { sql: '', args: [] };
65	  }
66	
67	  const clauses: string[] = [];
68	  const args: unknown[] = [];
69	
70	  for (const cond of conditions) {
71	    const extract = jsonExtract(cond.field);
72	
73	    switch (cond.op) {
74	      case 'eq':
75	        clauses.push(`${extract} = ?`);
76	        args.push(cond.value);
77	        break;
78	      case 'neq':
79	        clauses.push(`${extract} != ?`);
80	        args.push(cond.value);
81	        break;
82	      case 'gt':
83	        clauses.push(`${extract} > ?`);
84	        args.push(cond.value);
85	        break;
86	      case 'gte':
87	        clauses.push(`${extract} >= ?`);
88	        args.push(cond.value);
89	        break;
90	      case 'lt':
91	        clauses.push(`${extract} < ?`);
92	        args.push(cond.value);
93	        break;
94	      case 'lte':
95	        clauses.push(`${extract} <= ?`);
96	        args.push(cond.value);
97	        break;
98	      case 'like':
99	        clauses.push(`${extract} LIKE ?`);
100	        args.push(cond.value);
101	        break;
102	      case 'in': {
103	        if (cond.values.length === 0) {
104	          // Empty IN always returns false
105	          clauses.push('0');
106	        } else {
107	          const placeholders = cond.values.map(() => '?').join(', ');
108	          clauses.push(`${extract} IN (${placeholders})`);
109	          args.push(...cond.values);
110	        }
111	        break;
112	      }
113	      case 'isNull':
114	        clauses.push(`${extract} IS NULL`);
115	        break;
116	      case 'isNotNull':
117	        clauses.push(`${extract} IS NOT NULL`);
118	        break;
119	    }
120	  }
121	
122	  return {
123	    sql: ` WHERE ${clauses.join(' AND ')}`,
124	    args,
125	  };
126	}
127	
128	function buildOrderBy(
129	  orderBy?: Array<{ field: string; dir: 'asc' | 'desc' }>,
130	): string {
131	  if (!orderBy || orderBy.length === 0) return '';
132	  const parts = orderBy.map(
133	    ({ field, dir }) => `${jsonExtract(field)} ${dir === 'desc' ? 'DESC' : 'ASC'}`,
134	  );
135	  return ` ORDER BY ${parts.join(', ')}`;
136	}
137	
138	function buildLimit(limit?: number, offset?: number): SqlParts {
139	  const args: unknown[] = [];
140	  let sql = '';
141	  if (limit !== undefined) {
142	    sql += ' LIMIT ?';
143	    args.push(limit);
144	  }
145	  if (offset !== undefined) {
146	    sql += ' OFFSET ?';
147	    args.push(offset);
148	  }
149	  return { sql, args };
150	}
151	
152	// ── Parse helpers ─────────────────────────────────────────────────────
153	
154	function parseRow(row: Record<string, unknown>): BookEntry {
155	  return JSON.parse(row.content as string) as BookEntry;
156	}
157	
158	// ── SQLite Transaction ────────────────────────────────────────────────
159	
160	class SqliteTransaction implements BackendTransaction {
161	  constructor(private readonly db: DB) {
162	    this.db.exec('BEGIN');
163	  }
164	
165	  put(ref: BookRef, entry: BookEntry, opts?: { withPrev: boolean }): PutResult {
166	    const table = tableName(ref);
167	    const json = JSON.stringify(entry);
168	
169	    let prev: BookEntry | undefined;
170	    let created = true;
171	
172	    if (opts?.withPrev) {
173	      const existing = this.db
174	        .prepare(`SELECT content FROM "${table}" WHERE id = ?`)
175	        .get(entry.id) as { content: string } | undefined;
176	
177	      if (existing) {
178	        prev = JSON.parse(existing.content) as BookEntry;
179	        created = false;
180	      }
181	    } else {
182	      // Still need to know if it's a create or update for CDC
183	      const exists = this.db
184	        .prepare(`SELECT 1 FROM "${table}" WHERE id = ?`)
185	        .get(entry.id);
186	      created = !exists;
187	    }
188	
189	    this.db
190	      .prepare(
191	        `INSERT INTO "${table}" (id, content) VALUES (?, ?)
192	         ON CONFLICT(id) DO UPDATE SET content = excluded.content`,
193	      )
194	      .run(entry.id, json);
195	
196	    return { created, prev };
197	  }
198	
199	  patch(ref: BookRef, id: string, fields: Record<string, unknown>): PatchResult {
200	    const table = tableName(ref);
201	
202	    const existing = this.db
203	      .prepare(`SELECT content FROM "${table}" WHERE id = ?`)
204	      .get(id) as { content: string } | undefined;
205	
206	    if (!existing) {
207	      throw new Error(
208	        `[stacks] patch() failed: document "${id}" not found in ${ref.ownerId}/${ref.book}`,
209	      );
210	    }
211	
212	    const prev = JSON.parse(existing.content) as BookEntry;
213	    const updated = { ...prev, ...fields, id } as BookEntry;
214	    const json = JSON.stringify(updated);
215	
216	    this.db
217	      .prepare(`UPDATE "${table}" SET content = ? WHERE id = ?`)
218	      .run(json, id);
219	
220	    return { entry: updated, prev };
221	  }
222	
223	  delete(ref: BookRef, id: string, opts?: { withPrev: boolean }): DeleteResult {
224	    const table = tableName(ref);
225	
226	    if (opts?.withPrev) {
227	      // Fetch-then-delete in one logical step. Safe because we're
228	      // inside an explicit transaction (synchronous better-sqlite3).
229	      const existing = this.db
