1	/**
2	 * In-memory StacksBackend for tests.
3	 *
4	 * Exported via `@shardworks/stacks-apparatus/testing`. No SQLite dependency.
5	 * Implements the same contract as the SQLite backend.
6	 */
7	
8	import type {
9	  BackendOptions,
10	  BackendTransaction,
11	  BookRef,
12	  CountQuery,
13	  DeleteResult,
14	  InternalCondition,
15	  InternalQuery,
16	  PatchResult,
17	  PutResult,
18	  StacksBackend,
19	} from './backend.ts';
20	import type { BookEntry, BookSchema, Scalar } from './types.ts';
21	import { getNestedField, compareByOrderEntries } from './field-utils.ts';
22	
23	// ── Ref key ───────────────────────────────────────────────────────────
24	
25	function refKey(ref: BookRef): string {
26	  return `${ref.ownerId}/${ref.book}`;
27	}
28	
29	// ── Condition matching ────────────────────────────────────────────────
30	
31	function matchesCondition(entry: BookEntry, cond: InternalCondition): boolean {
32	  const value = getNestedField(entry, cond.field);
33	
34	  switch (cond.op) {
35	    case 'eq':       return value === cond.value;
36	    case 'neq':      return value !== cond.value;
37	    case 'gt':       return (value as number | string) > cond.value;
38	    case 'gte':      return (value as number | string) >= cond.value;
39	    case 'lt':       return (value as number | string) < cond.value;
40	    case 'lte':      return (value as number | string) <= cond.value;
41	    case 'like':     return sqlLike(String(value ?? ''), cond.value);
42	    case 'in':       return cond.values.includes(value as Scalar);
43	    case 'isNull':   return value == null;
44	    case 'isNotNull': return value != null;
45	  }
46	}
47	
48	/**
49	 * SQL LIKE matching — case-insensitive for ASCII only, matching SQLite behavior.
50	 *
51	 * SQLite's LIKE is case-insensitive for ASCII A-Z but case-sensitive for
52	 * Unicode characters. We replicate this by folding ASCII letters in both
53	 * value and pattern to lowercase before matching, rather than using the
54	 * regex 'i' flag (which would be case-insensitive for all Unicode).
55	 */
56	function sqlLike(value: string, pattern: string): boolean {
57	  // Fold ASCII letters only (matches SQLite behavior)
58	  const foldAscii = (s: string) =>
59	    s.replace(/[A-Z]/g, (c) => c.toLowerCase());
60	
61	  const foldedValue = foldAscii(value);
62	  const foldedPattern = foldAscii(pattern);
63	
64	  // Convert SQL LIKE pattern to regex: % → .*, _ → .
65	  // The escape class intentionally excludes % and _ so they survive to the
66	  // replacement step below where they become .* and . respectively.
67	  const escaped = foldedPattern.replace(/[.*+?^${}()|[\]\\]/g, (m) => '\\' + m);
68	  const regex = new RegExp(
69	    '^' + escaped.replace(/%/g, '.*').replace(/_/g, '.') + '$',
70	  );
71	  return regex.test(foldedValue);
72	}
73	
74	function matchesQuery(entry: BookEntry, query: CountQuery | InternalQuery): boolean {
75	  if (!query.where) return true;
76	  return query.where.every((cond) => matchesCondition(entry, cond));
77	}
78	
79	// ── Sorting ───────────────────────────────────────────────────────────
80	
81	function sortEntries(
82	  entries: BookEntry[],
83	  orderBy?: Array<{ field: string; dir: 'asc' | 'desc' }>,
84	): BookEntry[] {
85	  if (!orderBy || orderBy.length === 0) return entries;
86	  return [...entries].sort((a, b) => compareByOrderEntries(a, b, orderBy));
87	}
88	
89	// ── Pagination ────────────────────────────────────────────────────────
90	
91	function paginate(entries: BookEntry[], query: InternalQuery): BookEntry[] {
92	  let result = entries;
93	  if (query.offset !== undefined) {
94	    result = result.slice(query.offset);
95	  }
96	  if (query.limit !== undefined) {
97	    result = result.slice(0, query.limit);
98	  }
99	  return result;
100	}
101	
102	// ── Store ─────────────────────────────────────────────────────────────
103	
104	type Store = Map<string, Map<string, BookEntry>>;
105	
106	function cloneStore(store: Store): Store {
107	  const copy: Store = new Map();
108	  for (const [key, docs] of store) {
109	    copy.set(key, new Map(Array.from(docs).map(([id, doc]) => [id, structuredClone(doc)])));
110	  }
111	  return copy;
112	}
113	
114	function getBook(store: Store, ref: BookRef): Map<string, BookEntry> {
115	  const key = refKey(ref);
116	  let book = store.get(key);
117	  if (!book) {
118	    book = new Map();
119	    store.set(key, book);
120	  }
121	  return book;
122	}
123	
124	// ── Memory Transaction ────────────────────────────────────────────────
125	
126	class MemoryTransaction implements BackendTransaction {
127	  private committed = false;
128	  private rolledBack = false;
129	  private readonly snapshot: Store;
130	
131	  constructor(private readonly store: Store) {
132	    this.snapshot = cloneStore(store);
133	  }
134	
135	  private assertActive(): void {
136	    if (this.committed) {
137	      throw new Error('[stacks/memory] Cannot operate on a committed transaction');
138	    }
139	    if (this.rolledBack) {
140	      throw new Error('[stacks/memory] Cannot operate on a rolled-back transaction');
141	    }
142	  }
143	
144	  put(ref: BookRef, entry: BookEntry, opts?: { withPrev: boolean }): PutResult {
145	    this.assertActive();
146	    const book = getBook(this.store, ref);
147	    const existing = book.get(entry.id);
148	    const created = !existing;
149	    const prev = opts?.withPrev && existing ? structuredClone(existing) : undefined;
150	
151	    book.set(entry.id, structuredClone(entry));
152	    return { created, prev };
153	  }
154	
155	  patch(ref: BookRef, id: string, fields: Record<string, unknown>): PatchResult {
156	    this.assertActive();
157	    const book = getBook(this.store, ref);
158	    const existing = book.get(id);
159	
160	    if (!existing) {
161	      throw new Error(
162	        `[stacks/memory] patch() failed: document "${id}" not found in ${ref.ownerId}/${ref.book}`,
163	      );
164	    }
165	
166	    const prev = structuredClone(existing);
167	    const updated = { ...existing, ...fields, id } as BookEntry;
168	    book.set(id, structuredClone(updated));
169	
170	    return { entry: updated, prev };
171	  }
172	
173	  delete(ref: BookRef, id: string, opts?: { withPrev: boolean }): DeleteResult {
174	    this.assertActive();
175	    const book = getBook(this.store, ref);
176	    const existing = book.get(id);
177	
178	    if (!existing) return { found: false };
179	
180	    const prev = opts?.withPrev ? structuredClone(existing) : undefined;
181	    book.delete(id);
182	    return { found: true, prev };
183	  }
184	
185	  get(ref: BookRef, id: string): BookEntry | null {
186	    this.assertActive();
187	    const book = getBook(this.store, ref);
188	    const entry = book.get(id);
189	    return entry ? structuredClone(entry) : null;
190	  }
191	
192	  find(ref: BookRef, query: InternalQuery): BookEntry[] {
193	    this.assertActive();
194	    const book = getBook(this.store, ref);
195	    let entries = Array.from(book.values()).filter((e) => matchesQuery(e, query));
196	    entries = sortEntries(entries, query.orderBy);
197	    entries = paginate(entries, query);
198	    return entries.map((e) => structuredClone(e));
199	  }
200	
201	  count(ref: BookRef, query: CountQuery): number {
202	    this.assertActive();
203	    const book = getBook(this.store, ref);
204	    return Array.from(book.values()).filter((e) => matchesQuery(e, query)).length;
205	  }
206	
207	  commit(): void {
208	    this.committed = true;
209	  }
210	
211	  rollback(): void {
212	    if (this.committed) {
213	      throw new Error('[stacks/memory] Cannot rollback a committed transaction');
214	    }
215	    // Restore snapshot
216	    this.store.clear();
217	    for (const [key, docs] of this.snapshot) {
218	      this.store.set(key, docs);
219	    }
220	    this.rolledBack = true;
221	  }
222	}
223	
224	// ── Memory Backend ────────────────────────────────────────────────────
225	
226	export class MemoryBackend implements StacksBackend {
227	  private store: Store = new Map();
228	
229	  open(_options: BackendOptions): void {
230	    // No-op — memory backend is always ready
231	  }
232	
233	  close(): void {
234	    this.store.clear();
235	  }
236	
237	  ensureBook(ref: BookRef, _schema: BookSchema): void {
238	    // Ensure the book exists in the store (indexes are a no-op for memory)
239	    getBook(this.store, ref);
240	  }
241	
242	  beginTransaction(): BackendTransaction {
243	    return new MemoryTransaction(this.store);
244	  }
245	}
