1	/**
2	 * Conformance test helpers — create a StacksApi from a bare backend,
3	 * bypassing the guild startup machinery.
4	 *
5	 * Each test gets a fresh backend + API instance. No state leaks.
6	 */
7	
8	import assert from 'node:assert/strict';
9	import type { StacksBackend, BookRef } from '../backend.ts';
10	import type {
11	  BookEntry,
12	  StacksApi,
13	  ChangeEvent,
14	  ChangeHandler,
15	  CreateEvent,
16	  UpdateEvent,
17	  DeleteEvent,
18	  WatchOptions,
19	} from '../types.ts';
20	import { createTestableStacks } from './testable-stacks.ts';
21	
22	// ── Test factory ─────────────────────────────────────────────────────
23	
24	export interface TestStacks {
25	  stacks: StacksApi;
26	  backend: StacksBackend;
27	  /** Ensure a book exists (bypasses kit contribution flow). */
28	  ensureBook(ownerId: string, bookName: string, schema?: { indexes?: (string | string[])[] }): void;
29	  /** Seal the CDC registry (mirrors arbor's `phase:started` seal). */
30	  sealCdc(): void;
31	}
32	
33	export function createTestStacks(backendFactory: () => StacksBackend): TestStacks {
34	  const backend = backendFactory();
35	  backend.open({ home: '/tmp/stacks-test' });
36	
37	  const { api, sealCdc } = createTestableStacks(backend);
38	
39	  return {
40	    stacks: api,
41	    backend,
42	    ensureBook(ownerId: string, bookName: string, schema = {}) {
43	      backend.ensureBook({ ownerId, book: bookName }, schema);
44	    },
45	    sealCdc,
46	  };
47	}
48	
49	// ── Seed helper (bypasses CDC lock) ──────────────────────────────────
50	
51	export function seedDocument(
52	  backend: StacksBackend,
53	  ref: BookRef,
54	  entry: BookEntry,
55	): void {
56	  const tx = backend.beginTransaction();
57	  tx.put(ref, entry);
58	  tx.commit();
59	}
60	
61	// ── Event collector ──────────────────────────────────────────────────
62	
63	export function collectEvents<T extends BookEntry = BookEntry>(
64	  stacks: StacksApi,
65	  ownerId: string,
66	  bookName: string,
67	  options?: WatchOptions,
68	): ChangeEvent<T>[] {
69	  const events: ChangeEvent<T>[] = [];
70	  stacks.watch<T>(ownerId, bookName, ((event: ChangeEvent<T>) => {
71	    events.push(event);
72	  }) as ChangeHandler<T>, options);
73	  return events;
74	}
75	
76	// ── Backend spy (for 2.6 — verifying withPrev behavior) ─────────────
77	
78	export interface PutCall {
79	  ref: BookRef;
80	  entry: BookEntry;
81	  withPrev: boolean;
82	}
83	
84	/**
85	 * Wraps a backend factory to record put() calls on transactions,
86	 * so tests can verify whether withPrev was requested.
87	 */
88	export function spyingBackendFactory(
89	  factory: () => StacksBackend,
90	): { factory: () => StacksBackend; putCalls: PutCall[] } {
91	  const putCalls: PutCall[] = [];
92	
93	  const wrappedFactory = (): StacksBackend => {
94	    const backend = factory();
95	    const origBeginTransaction = backend.beginTransaction.bind(backend);
96	
97	    backend.beginTransaction = () => {
98	      const tx = origBeginTransaction();
99	      const origPut = tx.put.bind(tx);
100	
101	      tx.put = (ref, entry, opts) => {
102	        putCalls.push({ ref, entry, withPrev: opts?.withPrev ?? false });
103	        return origPut(ref, entry, opts);
104	      };
105	
106	      return tx;
107	    };
108	
109	    return backend;
110	  };
111	
112	  return { factory: wrappedFactory, putCalls };
113	}
114	
115	// ── CDC event assertion helpers ──────────────────────────────────────
116	
117	/** Assert the event is a `create` and check its fields. */
118	export function assertCreateEvent(
119	  event: ChangeEvent<BookEntry>,
120	  expected: { entry: BookEntry; ownerId?: string; book?: string },
121	): asserts event is CreateEvent<BookEntry> {
122	  assert.strictEqual(event.type, 'create');
123	  assert.deepStrictEqual(event.entry, expected.entry);
124	  if (expected.ownerId !== undefined) assert.strictEqual(event.ownerId, expected.ownerId);
125	  if (expected.book !== undefined) assert.strictEqual(event.book, expected.book);
126	}
127	
128	/** Assert the event is an `update` and check its fields. */
129	export function assertUpdateEvent(
130	  event: ChangeEvent<BookEntry>,
131	  expected: { entry: BookEntry; prev: BookEntry; ownerId?: string; book?: string },
132	): asserts event is UpdateEvent<BookEntry> {
133	  assert.strictEqual(event.type, 'update');
134	  assert.deepStrictEqual(event.entry, expected.entry);
135	  assert.deepStrictEqual(event.prev, expected.prev);
136	  if (expected.ownerId !== undefined) assert.strictEqual(event.ownerId, expected.ownerId);
137	  if (expected.book !== undefined) assert.strictEqual(event.book, expected.book);
138	}
139	
140	/** Assert the event is a `delete` and check its fields. */
141	export function assertDeleteEvent(
142	  event: ChangeEvent<BookEntry>,
143	  expected: { id: string; prev: BookEntry; ownerId?: string; book?: string },
144	): asserts event is DeleteEvent<BookEntry> {
145	  assert.strictEqual(event.type, 'delete');
146	  assert.strictEqual(event.id, expected.id);
147	  assert.deepStrictEqual(event.prev, expected.prev);
148	  if (expected.ownerId !== undefined) assert.strictEqual(event.ownerId, expected.ownerId);
149	  if (expected.book !== undefined) assert.strictEqual(event.book, expected.book);
150	}
151	
152	// ── Default book ref ─────────────────────────────────────────────────
153	
154	export const OWNER = 'test-owner';
155	export const BOOK = 'testbook';
156	export const REF: BookRef = { ownerId: OWNER, book: BOOK };
