1	/**
2	 * The Cartograph — vision/charge/piece decomposition-ladder apparatus.
3	 *
4	 * Stands up the data-and-typed-API substrate for the four-level
5	 * decomposition ladder:
6	 *
7	 *   vision (top, patron-owned, long-lived)
8	 *     → charge (first decomposition, the unit of patron walkthrough)
9	 *       → piece (recursive, internal organization, self-nesting)
10	 *         → mandate (existing leaf where rigs attach)
11	 *
12	 * Three writ types (`vision`, `charge`, `piece`) are contributed to the
13	 * Clerk via `clerk.registerWritType` from `start()`. Each type uses a
14	 * six-state mandate-clone lifecycle without `childrenBehavior` cascade —
15	 * patron-walkthrough semantics are coordinated by the typed API and
16	 * downstream consumers, not by registry-side cascade rules.
17	 *
18	 * Per-writ lifecycle stage lives on the Clerk's sanctioned plugin-keyed
19	 * metadata slot at `writ.ext['cartograph']`, written exclusively through
20	 * `clerk.setWritExt` so sibling sub-slots (e.g. `ext['surveyor']`) are
21	 * preserved under concurrent writers. The Cartograph contributes no
22	 * companion books — the writ row is the single source of truth for both
23	 * the framework-level lifecycle (writ.phase) and the cartograph-level
24	 * lifecycle (`ext['cartograph'].stage`).
25	 *
26	 * The typed API is the **only** layer that enforces the ladder's parent
27	 * invariants — vision has no parent, `charge.parentId` must be a vision,
28	 * `piece.parentId` must be a charge or piece. Raw `clerk.post({ type:
29	 * 'vision' })` continues to succeed without parent-type checks.
30	 *
31	 * Each `createX` opens a single `stacks.transaction(...)`, replicates
32	 * Clerk's `post()` validation byte-for-byte (parent existence,
33	 * parent-not-terminal, codex inheritance, id generation), writes the
34	 * writ row, and stamps `ext['cartograph']` via `clerk.setWritExt`. The
35	 * setWritExt's inner tx flattens via Stacks' nested-tx semantics, so
36	 * both writes commit atomically and CDC sees one coalesced `create`
37	 * event on the writs book. Each `transitionX` wraps `clerk.transition`
38	 * + `clerk.setWritExt('cartograph', ...)` in one outer transaction;
39	 * both inner txs flatten and CDC sees one coalesced `update` event.
40	 */
41	
42	import type { Plugin, StartupContext } from '@shardworks/nexus-core';
43	import { guild, generateId } from '@shardworks/nexus-core';
44	import type {
45	  StacksApi,
46	  WhereClause,
47	} from '@shardworks/stacks-apparatus';
48	import type {
49	  ClerkApi,
50	  WritDoc,
51	  WritPhase,
52	  WritTypeConfig,
53	} from '@shardworks/clerk-apparatus';
54	
55	import type {
56	  CartographApi,
57	  CartographExt,
58	  ChargeDoc,
59	  ChargeFilters,
