94	// ── Plugin identity ──────────────────────────────────────────────────
95	
96	/**
97	 * Plugin id used as the key into `writ.ext` for the cartograph's
98	 * sub-slot. By convention each plugin writes under its own pluginId;
99	 * the cartograph's id is `'cartograph'`. Centralised here so the
100	 * read paths and the write paths stay in lockstep.
101	 */
102	const CARTOGRAPH_PLUGIN_ID = 'cartograph';
103	
104	// ── Writ-type configs ────────────────────────────────────────────────
105	//
106	// Six-state mandate-clone byte-shape, identical to astrolabe's
107	// `STEP_CONFIG` / `OBSERVATION_SET_CONFIG`. NO `childrenBehavior`
108	// cascade — the typed API and downstream consumers coordinate
109	// patron-walkthrough semantics; the registry stays generic.
110	
111	const VISION_CONFIG: WritTypeConfig = {
112	  name: 'vision',
113	  states: [
114	    { name: 'new', classification: 'initial', allowedTransitions: ['open', 'cancelled'] },
115	    { name: 'open', classification: 'active', allowedTransitions: ['stuck', 'completed', 'failed', 'cancelled'] },
116	    { name: 'stuck', classification: 'active', attrs: ['stuck'], allowedTransitions: ['open', 'failed', 'cancelled'] },
117	    { name: 'completed', classification: 'terminal', attrs: ['success'], allowedTransitions: [] },
118	    { name: 'failed', classification: 'terminal', attrs: ['failure'], allowedTransitions: [] },
119	    { name: 'cancelled', classification: 'terminal', attrs: ['cancelled'], allowedTransitions: [] },
120	  ],
121	};
122	
123	const CHARGE_CONFIG: WritTypeConfig = {
124	  name: 'charge',
125	  states: [
126	    { name: 'new', classification: 'initial', allowedTransitions: ['open', 'cancelled'] },
127	    { name: 'open', classification: 'active', allowedTransitions: ['stuck', 'completed', 'failed', 'cancelled'] },
128	    { name: 'stuck', classification: 'active', attrs: ['stuck'], allowedTransitions: ['open', 'failed', 'cancelled'] },
129	    { name: 'completed', classification: 'terminal', attrs: ['success'], allowedTransitions: [] },
130	    { name: 'failed', classification: 'terminal', attrs: ['failure'], allowedTransitions: [] },
131	    { name: 'cancelled', classification: 'terminal', attrs: ['cancelled'], allowedTransitions: [] },
132	  ],
133	};
134	
135	const PIECE_CONFIG: WritTypeConfig = {
136	  name: 'piece',
137	  states: [
138	    { name: 'new', classification: 'initial', allowedTransitions: ['open', 'cancelled'] },
139	    { name: 'open', classification: 'active', allowedTransitions: ['stuck', 'completed', 'failed', 'cancelled'] },
140	    { name: 'stuck', classification: 'active', attrs: ['stuck'], allowedTransitions: ['open', 'failed', 'cancelled'] },
141	    { name: 'completed', classification: 'terminal', attrs: ['success'], allowedTransitions: [] },
142	    { name: 'failed', classification: 'terminal', attrs: ['failure'], allowedTransitions: [] },
143	    { name: 'cancelled', classification: 'terminal', attrs: ['cancelled'], allowedTransitions: [] },
144	  ],
145	};
146	
147	/**
148	 * Initial stage that pairs with a writ's `new` initial phase. The
149	 * typed-API `createX` methods set this in `ext['cartograph']` at
150	 * creation time so the slot starts in lockstep with the writ's phase.
151	 */
152	const INITIAL_STAGE = 'draft' as const;
153	
154	/**
155	 * Allowed initial (phase, stage) pairs for `createVision`. A vision
156	 * cannot be born retired, so terminal stages (`sunset`, `cancelled`)
157	 * are deliberately absent — to drive a vision to a terminal state,
158	 * create it then call `transitionVision`.
159	 *
160	 * The mapping mirrors the call-site logic the on-disk vision-apply tool
161	 * uses when deriving the writ phase from the patron's sidecar `stage`.
162	 */
163	const VISION_INITIAL_STAGE_TO_PHASE: Record<string, WritPhase> = {
164	  draft: 'new',
165	  active: 'open',
166	};
167	
168	/**
169	 * Return true when the given writ is in a terminal state per its
170	 * registered type config. Replicates `clerk.isTerminal()` against the
171	 * locally-resolved config so the call site doesn't need to round-trip
172	 * through the Clerk API mid-transaction.
173	 */
174	function isTerminalPhase(
175	  writ: WritDoc,
176	  getConfig: (name: string) => WritTypeConfig | undefined,
177	): boolean {
178	  const config = getConfig(writ.type);
179	  if (!config) {
180	    throw new Error(
181	      `[cartograph] writ "${writ.id}" carries unregistered type "${writ.type}".`,
182	    );
183	  }
184	  const state = config.states.find((s) => s.name === writ.phase);
185	  if (!state) {
186	    throw new Error(
187	      `[cartograph] writ "${writ.id}" carries phase "${writ.phase}" not declared in type "${writ.type}".`,
188	    );
189	  }
190	  return state.classification === 'terminal';
191	}
