565	          parentId: request.parentId,
566	          createdAt: now,
567	          updatedAt: now,
568	        };
569	
570	        await txWritsBook.put(writ);
571	
572	        const stamped = await clerk.setWritExt(
573	          childId,
574	          CARTOGRAPH_PLUGIN_ID,
575	          { stage: INITIAL_STAGE } satisfies CartographExt,
576	        );
577	        return projectCharge(stamped);
578	      });
579	    },
