642	    // ── Piece ─────────────────────────────────────────────────────
643	
644	    async createPiece(request: CreatePieceRequest): Promise<PieceDoc> {
645	      return stacks.transaction(async (tx) => {
646	        const txWritsBook = tx.book<WritDoc>('clerk', 'writs');
647	
648	        const childId = generateId('w', 6);
649	        const now = new Date().toISOString();
650	        const initialPhase = 'new';
651	
652	        if (!request.parentId) {
653	          throw new Error(
654	            '[cartograph] createPiece requires a parentId — a piece must be created under a charge or piece.',
655	          );
656	        }
657	
658	        const parent = await validateParent(txWritsBook, request.parentId, childId, {
659	          allowedParentTypes: ['charge', 'piece'],
660	          childTypeName: 'piece',
661	        });
662	
663	        const codex = request.codex ?? parent.codex;
664	
665	        const writ: WritDoc = {
666	          id: childId,
667	          type: 'piece',
668	          phase: initialPhase,
669	          title: request.title,
670	          body: request.body,
671	          ...(codex !== undefined ? { codex } : {}),
672	          parentId: request.parentId,
673	          createdAt: now,
674	          updatedAt: now,
675	        };
676	
677	        await txWritsBook.put(writ);
678	
679	        const stamped = await clerk.setWritExt(
680	          childId,
681	          CARTOGRAPH_PLUGIN_ID,
682	          { stage: INITIAL_STAGE } satisfies CartographExt,
683	        );
684	        return projectPiece(stamped);
685	      });
686	    },
687	
688	    async showPiece(id: string): Promise<PieceDoc> {
689	      const writ = await clerk.show(id);
690	      if (writ.type !== 'piece') {
691	        throw new Error(`Piece "${id}" not found (writ exists but type is "${writ.type}").`);
692	      }
693	      return projectPiece(writ);
694	    },
695	
696	    async listPieces(filters?: PieceFilters): Promise<PieceDoc[]> {
697	      const writsBook = stacks.readBook<WritDoc>('clerk', 'writs');
698	      const rows = await writsBook.find({
699	        where: buildListWhere(filters, 'piece'),
700	        orderBy: ['createdAt', 'desc'],
701	        limit: filters?.limit ?? 20,
702	        ...(filters?.offset !== undefined ? { offset: filters.offset } : {}),
703	      });
704	      return rows.map(tolerantProjectPiece);
705	    },
706	
707	    async patchPiece(
708	      id: string,
709	      fields: Partial<Omit<PieceDoc, 'id'>>,
710	    ): Promise<PieceDoc> {
711	      return stacks.transaction(async () => {
712	        const codex = fields.codex as string | undefined;
713	        const stage = fields.stage as PieceStage | undefined;
714	        if (codex !== undefined) {
715	          await clerk.edit({ id, codex });
716	        }
717	        if (stage !== undefined) {
718	          await clerk.setWritExt(
719	            id,
720	            CARTOGRAPH_PLUGIN_ID,
721	            { stage } satisfies CartographExt,
722	          );
723	        }
724	        const writ = await clerk.show(id);
725	        return projectPiece(writ);
726	      });
727	    },
728	
729	    async transitionPiece(
730	      id: string,
731	      request: TransitionPieceRequest,
732	    ): Promise<PieceDoc> {
733	      return stacks.transaction(async () => {
734	        const transitionFields: Partial<WritDoc> = {};
735	        if (request.resolution !== undefined) {
736	          transitionFields.resolution = request.resolution;
737	        }
738	        await clerk.transition(id, request.phase, transitionFields);
739	
740	        const stamped = await clerk.setWritExt(
741	          id,
742	          CARTOGRAPH_PLUGIN_ID,
743	          { stage: request.stage } satisfies CartographExt,
744	        );
745	        return projectPiece(stamped);
746	      });
747	    },
748	  };
749	
750	  // ── Apparatus ─────────────────────────────────────────────────────
751	
752	  return {
753	    apparatus: {
754	      requires: ['stacks', 'clerk'],
755	      // Recommend `oculus` so the writs page renders the new types via
756	      // its type-vocabulary helper. Without oculus the data is invisible
757	      // to the dashboard; recommending it surfaces a clean startup
758	      // warning when an operator forgets.
759	      recommends: ['oculus'],
760	
761	      supportKit: {
762	        // Cartograph contributes 16 patron-facing CLI tools — five per
763	        // (vision/charge/piece × create/show/list/patch/transition) plus
764	        // the on-disk authoring tool `vision-apply`. The framework
765	        // `nsg` auto-builder discovers them via The Instrumentarium and
766	        // groups them by hyphen prefix automatically (D2/D3 in the
767	        // commission spec). No companion books are contributed —
768	        // per-writ stage lives in the Clerk's `writ.ext['cartograph']`
769	        // sub-slot, written through `clerk.setWritExt`.
770	        tools: [
771	          visionCreate,
772	          visionShow,
773	          visionList,
774	          visionPatch,
775	          visionTransition,
776	          visionApply,
777	          chargeCreate,
778	          chargeShow,
779	          chargeList,
780	          chargePatch,
781	          chargeTransition,
782	          pieceCreate,
783	          pieceShow,
784	          pieceList,
785	          piecePatch,
786	          pieceTransition,
787	        ],
788	      },
789	
790	      provides: api,
791	
792	      start(_ctx: StartupContext): void {
793	        const g = guild();
794	        stacks = g.apparatus<StacksApi>('stacks');
795	        clerk = g.apparatus<ClerkApi>('clerk');
796	
797	        // Register the three writ types. Cartograph's `requires: ['stacks',
798	        // 'clerk']` declaration ensures Clerk has already started; the
799	        // registration window stays open until the framework's
800	        // `phase:started` signal seals it.
801	        clerk.registerWritType(VISION_CONFIG);
802	        clerk.registerWritType(CHARGE_CONFIG);
803	        clerk.registerWritType(PIECE_CONFIG);
804	      },
805	    },
806	  };
807	}
808	
809	// Re-export the type-config constants so tests can assert them without
810	// reaching back into the apparatus module.
811	export { VISION_CONFIG, CHARGE_CONFIG, PIECE_CONFIG, CARTOGRAPH_PLUGIN_ID };
812	
813	// Local type re-exports kept narrow — see ./index.ts for the full surface.
814	export type {
815	  ChargeStage,
816	  PieceStage,
817	  VisionStage,
818	  WritPhase,
819	};
