export interface StacksApi {
  book<T extends BookEntry>(ownerId: string, name: string): Book<T>;
  readBook<T extends BookEntry>(ownerId: string, name: string): ReadOnlyBook<T>;

  watch<T extends BookEntry>(
    ownerId: string,
    bookName: string,
    handler: ChangeHandler<T>,
    options?: WatchOptions,
  ): void;

  transaction<R>(fn: (tx: TransactionContext) => Promise<R>): Promise<R>;

  /**
   * Retire a book — drop its underlying storage and fire a single
   * `delete-book` CDC event after the drop succeeds.
   *
   * Semantics:
   *   - **Idempotent.** Silent no-op when the book does not exist;
   *     mirrors `Book.delete(id)` and SQLite's `DROP TABLE IF EXISTS`.
   *   - **Single book-level event.** Fires exactly one `delete-book`
   *     `ChangeEvent` with payload `{ type, ownerId, book }`. No
   *     per-row delete events are emitted, even on a populated book.
   *   - **Phase 2 only.** The event is delivered post-commit; rolling
   *     back via a Phase-1 handler would create a confusing
   *     "drop sometimes" contract.
   *   - **Top-level only.** Throws if invoked while a `transaction(...)`
   *     is open in the caller's context. DDL (book-drop) is not allowed
   *     to participate in DML transactions.
   *   - **Watchers stay registered.** Any CDC watcher registered for
   *     the dropped book remains in the registry but becomes dormant
   *     (no future writes can fire it). The post-`phase:started`
   *     registry-immutability invariant is preserved.
   */
  dropBook(ownerId: string, bookName: string): Promise<void>;
}

