  ownerId: string;
  book: string;
  id: string;
  prev: T;
}

/**
 * Whole-book retirement event fired by `StacksApi.dropBook` after the
 * backend has dropped the underlying storage. Carries only the owner
 * and book identifiers — no per-row payload — because a drop is a
 * single book-level event, not a fan-out of per-row deletes.
 *
 * Delivered Phase 2 only (post-commit notification semantics): a drop
 * is irreversible from the caller's perspective, so a Phase-1 handler
 * cannot meaningfully roll it back.
 */
export interface BookDeleteEvent {
  type: 'delete-book';
  ownerId: string;
  book: string;
}

export type ChangeEvent<T extends BookEntry> =
  | CreateEvent<T>
  | UpdateEvent<T>
  | DeleteEvent<T>
  | BookDeleteEvent;

export type ChangeHandler<T extends BookEntry = BookEntry> = (
  event: ChangeEvent<T>,
) => Promise<void> | void;

export interface WatchOptions {
  /**
   * Controls when the handler runs relative to the transaction commit.
   *
   * true  (default) — Phase 1: runs INSIDE the transaction. Handler writes
   *   join the same transaction. If the handler throws, everything rolls back.
   *
   * false — Phase 2: runs AFTER the transaction commits. Errors are logged
   *   as warnings but do not affect committed data.
   *
   * @default true
   */
  failOnError?: boolean;
}

// ── StacksApi — the `provides` interface ──────────────────────────────

export interface TransactionContext {
  book<T extends BookEntry>(ownerId: string, name: string): Book<T>;
  readBook<T extends BookEntry>(ownerId: string, name: string): ReadOnlyBook<T>;
}

export interface StacksApi {
  book<T extends BookEntry>(ownerId: string, name: string): Book<T>;
  readBook<T extends BookEntry>(ownerId: string, name: string): ReadOnlyBook<T>;

  watch<T extends BookEntry>(
    ownerId: string,
    bookName: string,
    handler: ChangeHandler<T>,
    options?: WatchOptions,
  ): void;

  transaction<R>(fn: (tx: TransactionContext) => Promise<R>): Promise<R>;
}

/**
 * @shardworks/stacks-apparatus — The Stacks apparatus.
