 * Guild persistence layer: NoSQL document store with CDC, transactions,
 * and swappable backend. Default export is the apparatus plugin.
 *
 * See: docs/specification.md
 */

import { createStacksApparatus } from './stacks.ts';

// ── Public types ──────────────────────────────────────────────────────

export type {
  // Plugin config
  StacksConfig,

  // Document model
  BookEntry,
  BookSchema,

  // Book handles
  Book,
  ReadOnlyBook,

  // Query language
  Scalar,
  WhereCondition,
  WhereClause,
  OrderEntry,
  OrderBy,
  Pagination,
  BookQuery,
  ListOptions,

  // CDC
  ChangeEvent,
  CreateEvent,
  UpdateEvent,
  DeleteEvent,
  ChangeHandler,
  WatchOptions,

  // API
  StacksApi,
  TransactionContext,
} from './types.ts';

