// ── Book retirement ───────────────────────────────────────────────

/**
 * Imperative whole-book retirement (D1, D3, D5, D6).
 *
 * Drops the backend storage for the book and, on success, fires a
 * single Phase-2 `delete-book` CDC event (D3, D9). Refuses to run
 * inside an active transaction (D6) — DDL is hard-separated from DML
 * by the substrate.
 *
 * Idempotent: a missing book is a silent no-op (D2). Watchers
 * registered for the dropped book are not unregistered (D14); they
 * remain in the registry but become dormant because no future writes
 * can fire them.
 */
async doDropBook(ownerId: string, bookName: string): Promise<void> {
  if (this.activeTx) {
    throw new Error(
      `[stacks] dropBook("${ownerId}", "${bookName}") refused: a transaction is active. ` +
      `Book-drop is DDL and cannot participate in DML transactions — ` +
      `move the dropBook call outside transaction(...).`,
    );
  }

  await this.backend.dropBook({ ownerId, book: bookName });

  // Phase-2 only (D5): a book-drop is irreversible from the caller's
  // perspective, so a Phase-1 handler couldn't meaningfully roll it
  // back. Wrap in the same depth tracking as transactional Phase-2
  // delivery so a `delete-book` handler that opens a transaction
  // observes the same cross-transaction re-entry bound.
  this.phase2Depth++;
  try {
    await this.cdc.firePhase2([
      { type: 'delete-book', ownerId, book: bookName },
    ]);
  } finally {
    this.phase2Depth--;
  }
}

// ── Read operations ───────────────────────────────────────────────

