});

it('dropBook() of an unknown book emits no book-dropped event when the book was never declared', async () => {
  // The bridge only watches declared books. A drop call for an
  // owner/book pair that the bridge never wired up cannot produce a
  // bridge-emitted event — there is no Phase-2 watcher to fire.
  const fix = await buildFixture();

  await fix.stacks.dropBook('never-declared', 'phantom');

  assert.equal(await fix.countAfter(), 0);
});

