    it('2.22 Coalescing: delete (single, existing doc) produces delete with pre-transaction prev', async () => {
      seedDocument(t.backend, REF, { id: 'a', name: 'Alice' });
      const events = collectEvents(t.stacks, OWNER, BOOK, { failOnError: false });

      await t.stacks.transaction(async (tx) => {
        const book = tx.book<BookEntry>(OWNER, BOOK);
        await book.delete('a');
      });

      assert.strictEqual(events.length, 1);
      assertDeleteEvent(events[0], { id: 'a', prev: { id: 'a', name: 'Alice' } });
    });

    // ── dropBook CDC behaviour ───────────────────────────────────────

    it('2.23 dropBook fires exactly one delete-book event with the correct shape', async () => {
      // Seed a populated book to confirm dropBook does NOT fan out into
      // per-row delete events (D3) — the fire is exactly one book-level
      // event with the minimal D9 payload `{ type, ownerId, book }`.
      // Phase-2 only (D5) — registered via the same watch() used for
      // row events.
      seedDocument(t.backend, REF, { id: 'a', name: 'Alice' });
      seedDocument(t.backend, REF, { id: 'b', name: 'Bob' });
      seedDocument(t.backend, REF, { id: 'c', name: 'Charlie' });

      const events = collectEvents(t.stacks, OWNER, BOOK, { failOnError: false });

      await t.stacks.dropBook(OWNER, BOOK);

      assert.strictEqual(events.length, 1, 'exactly one event — no per-row fan-out');
      const event = events[0];
      assert.strictEqual(event.type, 'delete-book');
      assert.strictEqual(event.ownerId, OWNER);
      assert.strictEqual(event.book, BOOK);

      // Minimal payload (D9): exactly the three identifier fields, no
      // entry/prev/id, no rowCount, no timestamp.
      assert.deepStrictEqual(
        Object.keys(event).sort(),
        ['book', 'ownerId', 'type'],
      );
    });

    it('2.24 dropBook does not fire delete-book to handlers on other books', async () => {
      // Owner-scoped delivery: a delete-book on (OWNER, BOOK) must not
      // be visible to a watcher registered for (OWNER, otherBook).
      const otherBook = 'otherbook';
      t.ensureBook(OWNER, otherBook);

      const eventsForOther = collectEvents(
        t.stacks, OWNER, otherBook, { failOnError: false },
      );

      await t.stacks.dropBook(OWNER, BOOK);

      assert.strictEqual(eventsForOther.length, 0);
    });
  });
}

