768	        // per-writ stage lives in the Clerk's `writ.ext['cartograph']`
769	        // sub-slot, written through `clerk.setWritExt`.
770	        tools: [
771	          visionCreate,
772	          visionShow,
773	          visionList,
774	          visionPatch,
775	          visionTransition,
776	          visionApply,
777	          chargeCreate,
778	          chargeShow,
779	          chargeList,
780	          chargePatch,
781	          chargeTransition,
782	          pieceCreate,
783	          pieceShow,
784	          pieceList,
785	          piecePatch,
