393	    it('2.14a-phase2 Phase-2 cross-transaction re-entry depth limiting prevents infinite chains', async () => {
394	      // Sibling to 2.14a: the Phase-1 cascade-depth bound caps handler
395	      // nesting *within* a transaction. The Phase-2 bound caps chains
396	      // of post-commit hops where each handler's write opens a fresh
397	      // transaction (so the Phase-1 counter resets at each hop). The
398	      // test installs a self-cycling Phase-2 watcher and verifies:
399	      //   (a) the substrate-level Phase-2 bound trips with a distinct
400	      //       error literal mentioning "Phase-2 re-entry depth" (D8),
401	      //   (b) hops 1..N-1 committed durably (D10 partial-commit) — the
402	      //       counter advances past the seeded value but stops at the
403	      //       last successfully committed hop,
404	      //   (c) the chain terminates within bounded wall time (the test
405	      //       runner's per-test timeout asserts this implicitly — an
406	      //       unbounded chain would hang forever).
407	      seedDocument(t.backend, REF, { id: 'a', counter: 0 });
408	
409	      t.stacks.watch(OWNER, BOOK, async (event) => {
410	        // Skip both `delete` (no entry) and `delete-book` (no per-row
