412	        // writes.
413	        if (event.type === 'create' || event.type === 'update') {
414	          const book = t.stacks.book<BookEntry>(OWNER, BOOK);
415	          await book.put({
416	            ...event.entry,
417	            counter: ((event.entry as any).counter ?? 0) + 1,
418	          });
419	        }
420	      }, { failOnError: false });
421	
422	      const book = t.stacks.book<BookEntry>(OWNER, BOOK);
423	      const start = Date.now();
424	
425	      // (a) Distinct error literal — must mention "Phase-2 re-entry depth"
426	      // and must NOT match the Phase-1 cascade-depth wording. The Phase-1
427	      // regex from 2.14a is /cascade depth|Maximum cascade depth/ — the
428	      // Phase-2 regex below is intentionally disjoint.
429	      await assert.rejects(
430	        () => book.put({ id: 'a', counter: 1 }),
431	        /Phase-2 re-entry depth/,
432	      );
433	
434	      // (c) Bounded wall time — guard against a future implementation
435	      // accidentally letting the chain run further than expected (a
436	      // tighter local bound than the test runner's default).
437	      const elapsed = Date.now() - start;
438	      assert.ok(
439	        elapsed < 5000,
440	        `Phase-2 chain should terminate within bounded wall time; took ${elapsed}ms`,
441	      );
442	
443	      // (b) Partial-commit semantics — the initial trigger committed
444	      // (counter=1), then N-1 successful Phase-2 hops each advanced the
445	      // counter by 1 before hop N's write was rejected. The exact final
446	      // value depends on the substrate's MAX_PHASE2_REENTRY_DEPTH. We
447	      // assert the *shape* (advanced past seed, well below an unbounded
448	      // run) rather than pinning the exact constant — that lives in
449	      // stacks-core.ts and is intentionally not re-exported.
450	      const result = await book.get('a');
451	      assert.notStrictEqual(result, null, 'document should still exist');
452	      const finalCounter = (result as any).counter as number;
453	      assert.ok(
454	        finalCounter > 1,
455	        `expected counter to advance past seed via committed Phase-2 hops, ` +
456	        `got ${finalCounter}`,
457	      );
458	      assert.ok(
459	        finalCounter < 1000,
460	        `expected counter to stop at the substrate bound, but it ran to ${finalCounter} — ` +
461	        `the Phase-2 re-entry bound did not contain the chain`,
462	      );
463	    });
