/**
 * Conformance suite — SqliteBackend
 *
 * Runs all conformance tiers against the on-disk SQLite backend. Each
 * backend instance opens a fresh SQLite database under a per-test
 * temporary directory so test cases cannot pollute each other through
 * shared state.
 *
 * The shared `createTestStacks` helper unconditionally calls
 * `backend.open({ home: '/tmp/stacks-test' })`, so this file's factory
 * shadows `open()` on each new SqliteBackend with a closure that
 * substitutes a private tmp dir before delegating to the real open path.
 */
import { describe } from 'node:test';
import fs from 'node:fs';
import os from 'node:os';
import path from 'node:path';

import type { StacksBackend } from './backend.ts';
import { SqliteBackend } from './sqlite-backend.ts';
import { runConformanceSuite } from './conformance/suite.ts';

function sqliteFactory(): StacksBackend {
  const home = fs.mkdtempSync(path.join(os.tmpdir(), 'stacks-sqlite-'));
  fs.mkdirSync(path.join(home, '.nexus'), { recursive: true });

  const backend = new SqliteBackend();
  // Shadow open() so the conformance helper's hard-coded
  // `home: '/tmp/stacks-test'` is ignored in favour of this instance's
  // private tmp dir. Every other method delegates to the real backend.
  const origOpen = backend.open.bind(backend);
  backend.open = () => origOpen({ home });
  return backend;
}

describe('Stacks Conformance — SqliteBackend', () => {
  runConformanceSuite('SqliteBackend', sqliteFactory);
});

