// ── Query builder ─────────────────────────────────────────────────────

interface SqlParts {
  sql: string;
  args: unknown[];
}

/**
 * Translate a JS scalar into a SQLite-bindable value. better-sqlite3
 * rejects JS booleans as bind parameters, but SQLite's `json_extract`
 * surfaces stored JSON booleans as the integer literals `0` / `1`. So
 * we coerce on the bind side: `true → 1`, `false → 0`. Other scalars
 * (string, number, null, bigint, buffer) pass through unchanged.
 */
function bindScalar(value: unknown): unknown {
  if (typeof value === 'boolean') return value ? 1 : 0;
  return value;
}

function buildWhere(conditions?: InternalCondition[]): SqlParts {
  if (!conditions || conditions.length === 0) {
    return { sql: '', args: [] };
  }

  const clauses: string[] = [];
  const args: unknown[] = [];

  for (const cond of conditions) {
    const extract = jsonExtract(cond.field);

    switch (cond.op) {
      case 'eq':
        clauses.push(`${extract} = ?`);
        args.push(bindScalar(cond.value));
        break;
      case 'neq':
        clauses.push(`${extract} != ?`);
        args.push(bindScalar(cond.value));
        break;
      case 'gt':
        clauses.push(`${extract} > ?`);
        args.push(bindScalar(cond.value));
        break;
      case 'gte':
        clauses.push(`${extract} >= ?`);
        args.push(bindScalar(cond.value));
        break;
      case 'lt':
        clauses.push(`${extract} < ?`);
        args.push(bindScalar(cond.value));
        break;
      case 'lte':
        clauses.push(`${extract} <= ?`);
        args.push(bindScalar(cond.value));
        break;
      case 'like':
        clauses.push(`${extract} LIKE ?`);
        args.push(bindScalar(cond.value));
        break;
      case 'in': {
        if (cond.values.length === 0) {
          // Empty IN always returns false
          clauses.push('0');
        } else {
          const placeholders = cond.values.map(() => '?').join(', ');
          clauses.push(`${extract} IN (${placeholders})`);
          args.push(...cond.values.map(bindScalar));
