// ── dropBook edge cases ──────────────────────────────────────────

it('4.12 dropBook on a missing book is a silent no-op', async () => {
  // Idempotency precedent (D2): mirrors `Book.delete(id)` and SQLite's
  // `DROP TABLE IF EXISTS`. Calling dropBook on a book that was never
  // ensured must not throw.
  await t.stacks.dropBook(OWNER, 'never-ensured-book');
});

it('4.13 dropBook then ensureBook recreates a fresh empty book', async () => {
  const book = t.stacks.book<BookEntry>(OWNER, BOOK);
  await book.put({ id: 'a', name: 'Alice' });
  await book.put({ id: 'b', name: 'Bob' });

  await t.stacks.dropBook(OWNER, BOOK);
  // Re-declare schema — backends must accept this idempotent call as
  // a fresh book (no rows from the prior incarnation).
  t.backend.ensureBook(REF, {});

  const after = t.stacks.book<BookEntry>(OWNER, BOOK);
  assert.deepStrictEqual(await after.list(), []);

  // And the recreated book accepts new writes without error.
  await after.put({ id: 'c', name: 'Charlie' });
  assert.deepStrictEqual(await after.get('c'), { id: 'c', name: 'Charlie' });
});

it('4.14 dropBook inside an active transaction throws', async () => {
  // D6: hard separation of DDL from DML. The substrate refuses the
  // mix rather than rationalizing it.
  await assert.rejects(
    () =>
      t.stacks.transaction(async () => {
        await t.stacks.dropBook(OWNER, BOOK);
      }),
    /transaction is active|cannot participate/i,
  );
});

it('4.15 dropBook succeeds when watchers are registered for the dropped book', async () => {
  // D14: drop succeeds silently; any registered watcher remains
  // dormant in the registry. The post-`phase:started` registry-
  // immutability invariant is preserved (we don't auto-unregister).
  const events = collectEvents(t.stacks, OWNER, BOOK, { failOnError: false });
  // Plus a Phase-1 watcher to confirm both phases survive the drop.
  let phase1Calls = 0;
  t.stacks.watch(OWNER, BOOK, () => { phase1Calls += 1; }, { failOnError: true });

  await t.stacks.dropBook(OWNER, BOOK);

  // The Phase-2 watcher receives exactly one delete-book event.
  assert.strictEqual(events.length, 1);
  assert.strictEqual(events[0].type, 'delete-book');
  // Phase-1 watchers do NOT receive delete-book (it is Phase 2 only,
  // per D5) and so were never invoked.
  assert.strictEqual(phase1Calls, 0);
});

