async start(_ctx: StartupContext): Promise<void> {
  const g = guild();
  stacks = g.apparatus<StacksApi>('stacks');
  clerk = g.apparatus<ClerkApi>('clerk');

  // Retro-cleanup of three companion books that earlier versions
  // of the cartograph kit declared and have since been removed.
  // The substrate's schema reconciliation is additive only — kit
  // contributions cannot remove a book — so the abandoned tables
  // would otherwise persist on every existing on-disk database
  // forever. `stacks.dropBook` is the sanctioned imperative
  // retirement primitive and is idempotent (silent no-op on a
  // missing book), so subsequent boots are no-ops on guilds that
  // were already cleaned up. Issued sequentially before any
  // `clerk.registerWritType` call (D11, D15) — "erase the dead,
  // then declare the live" — and outside any active transaction
  // because dropBook is DDL and refuses to participate in DML
  // transactions (D6).
  await stacks.dropBook(CARTOGRAPH_PLUGIN_ID, 'visions');
  await stacks.dropBook(CARTOGRAPH_PLUGIN_ID, 'charges');
  await stacks.dropBook(CARTOGRAPH_PLUGIN_ID, 'pieces');

  // Register the three writ types. Cartograph's `requires: ['stacks',
  // 'clerk']` declaration ensures Clerk has already started; the
  // registration window stays open until the framework's
  // `phase:started` signal seals it.
  clerk.registerWritType(VISION_CONFIG);
  clerk.registerWritType(CHARGE_CONFIG);
  clerk.registerWritType(PIECE_CONFIG);
},

