// ── Retro-cleanup of retired companion books ─────────────────────

describe('retro-cleanup', () => {
  it('drops cartograph/visions, charges, and pieces during start()', async () => {
    // Spec'd commission D11/D15: cartograph.start() must call
    // stacks.dropBook for the three retired companion books — earlier
    // versions of the kit declared them, so they accumulate as
    // dead-but-not-dropped storage on every existing on-disk database.
    // Verified via a recording wrapper around StacksApi.
    const dropCalls: Array<{ ownerId: string; bookName: string }> = [];

    // Build a minimal harness mirroring buildFixture, but interpose a
    // recording proxy on stacks before cartograph.start() runs.
    const memBackend = new MemoryBackend();
    const stacksPlugin = createStacksApparatus(memBackend);
    const clerkPlugin = createClerk();
    const cartographPlugin = createCartograph();

    const apparatusMap = new Map<string, unknown>();

    const fakeGuildConfig: GuildConfig = {
      name: 'cartograph-retro-cleanup-test',
      nexus: '0.0.0',
      plugins: [],
    };

    const fakeGuild: Guild = {
      home: '/tmp/cartograph-retro-cleanup-test',
      apparatus<T>(name: string): T {
        const a = apparatusMap.get(name);
        if (!a) throw new Error(`Apparatus "${name}" not installed`);
        return a as T;
      },
      tryApparatus<T>(name: string): T | null {
        try { return this.apparatus<T>(name); } catch { return null; }
      },
      config<T>(_pluginId: string): T { return {} as T; },
      writeConfig(): void {},
      guildConfig(): GuildConfig { return fakeGuildConfig; },
      kits(): LoadedKit[] { return []; },
      apparatuses(): LoadedApparatus[] { return []; },
      failedPlugins() { return []; },
      startupWarnings(): string[] { return []; },
    };
    setGuild(fakeGuild);

    try {
      stacksPlugin.apparatus.start!(buildCtx());
      const realStacks = stacksPlugin.apparatus.provides as StacksApi;

      // Record every dropBook call without altering behaviour.
      const recordingStacks: StacksApi = {
        ...realStacks,
        dropBook: async (ownerId: string, bookName: string) => {
          dropCalls.push({ ownerId, bookName });
          return realStacks.dropBook(ownerId, bookName);
        },
      };
      apparatusMap.set('stacks', recordingStacks);

      memBackend.ensureBook({ ownerId: 'clerk', book: 'writs' }, {
        indexes: ['phase', 'type', 'createdAt', 'parentId'],
      });
      memBackend.ensureBook({ ownerId: 'clerk', book: 'links' }, {
        indexes: ['sourceId', 'targetId', 'label'],
      });

      await clerkPlugin.apparatus.start!(buildCtx());
      const clerk = clerkPlugin.apparatus.provides as ClerkApi;
      apparatusMap.set('clerk', clerk);

      await cartographPlugin.apparatus.start!(buildCtx());

      // The three retro-cleanup calls must have fired in order, and
      // before any other dropBook call. There are no other dropBook
      // calls in cartograph today.
      assert.deepEqual(
        dropCalls,
        [
          { ownerId: 'cartograph', bookName: 'visions' },
          { ownerId: 'cartograph', bookName: 'charges' },
          { ownerId: 'cartograph', bookName: 'pieces' },
        ],
        'cartograph.start() must drop visions, charges, pieces in that order',
      );
    } finally {
      clearGuild();
    }
  });

  it('subsequent boots are no-ops on a fresh database (idempotent dropBook)', async () => {
    // The first buildFixture() — implicit in beforeEach — already ran
    // the three dropBook calls. A second cartograph.start() against a
    // fresh database (where no companion-table residue exists) must
    // succeed silently because dropBook is a no-op on missing books
    // (D2). Build a separate fixture and confirm no error.
    const second = await buildFixture();
    // If we got here, start() succeeded — a missing-book drop did not
    // throw. The fixture is fully wired.
    assert.ok(second.cartograph);
    clearGuild();
  });
});

