1	/**
2	 * Stacks core — shared implementation logic for both the production
3	 * apparatus (stacks.ts) and the testable harness (testable-stacks.ts).
4	 *
5	 * This module contains ALL read/write/transaction/CDC logic. The two
6	 * consumer modules only add their own wiring: the apparatus adds guild()
7	 * startup and plugin schema reconciliation; the testable harness adds
8	 * nothing (just exposes createApi() directly).
9	 *
10	 * This ensures behavioral identity by construction, not by copy-paste.
11	 */
12	
13	import type {
14	  BackendTransaction,
15	  BookRef,
16	  InternalQuery,
17	  StacksBackend,
18	} from './backend.ts';
19	
20	import type {
21	  Book,
22	  BookEntry,
23	  BookQuery,
24	  ListOptions,
25	  ReadOnlyBook,
26	  StacksApi,
27	  TransactionContext,
28	  WatchOptions,
29	  WhereClause,
30	  ChangeHandler,
31	} from './types.ts';
32	
33	import {
34	  CdcRegistry,
35	  coalesceEvents,
36	  Phase2DepthExceededError,
37	  type BufferedEvent,
38	} from './cdc.ts';
39	import { translateQuery, translateWhereClause } from './query.ts';
40	import { normalizeOrderBy, compareByOrderEntries } from './field-utils.ts';
41	
42	// ── Constants ────────────────────────────────────────────────────────
43	
44	/**
45	 * Phase-1 cascade-depth bound — caps in-transaction handler nesting so
46	 * a Phase-1 watcher that re-triggers itself cannot pin the CPU. Counted
47	 * per-transaction inside `ActiveTransaction.depth`.
48	 */
49	const MAX_CASCADE_DEPTH = 16;
50	
51	/**
52	 * Phase-2 cross-transaction re-entry depth bound — caps the number of
53	 * post-commit handler hops in a single Phase-2 chain. The Phase-1 guard
54	 * resets when each Phase-2 handler opens its own transaction, so a
55	 * separate counter is required to bound Phase-2 cycles. Counted at the
56	 * `firePhase2` boundary inside `phase2Depth` (D3, D4, D5).
57	 *
58	 * The two bounds are intentionally orthogonal: Phase-1 measures handler
59	 * nesting within one transaction; Phase-2 measures post-commit hops
60	 * across transactions. Sharing a single budget would false-positive
61	 * deep cascade graphs.
62	 */
63	const MAX_PHASE2_REENTRY_DEPTH = 16;
64	
65	// ── Active transaction state ──────────────────────────────────────────
66	
67	interface ActiveTransaction {
68	  backendTx: BackendTransaction;
69	  eventBuffer: BufferedEvent[];
70	  depth: number;
71	}
72	
73	// ── Book handle implementation ────────────────────────────────────────
74	
75	function createBookHandle<T extends BookEntry>(
76	  ref: BookRef,
77	  core: StacksCore,
78	  writable: boolean,
79	): Book<T> {
80	  const readMethods: ReadOnlyBook<T> = {
81	    async get(id: string): Promise<T | null> {
82	      return core.doGet(ref, id) as T | null;
83	    },
84	
85	    async find(query: BookQuery): Promise<T[]> {
86	      return core.doFind(ref, query) as Promise<T[]>;
87	    },
88	
89	    async list(options?: ListOptions): Promise<T[]> {
90	      // Cast needed: ListOptions spreads into BookQuery but the Pagination
91	      // discriminated union can't be inferred from optional fields.
92	      return core.doFind(ref, {
93	        orderBy: options?.orderBy,
94	        limit: options?.limit,
95	        offset: options?.offset,
96	      } as BookQuery) as Promise<T[]>;
97	    },
98	
99	    async count(where?: WhereClause | { or: WhereClause[] }): Promise<number> {
100	      return core.doCount(ref, where);
101	    },
102	  };
103	
104	  if (!writable) {
105	    return readMethods as Book<T>;
106	  }
107	
108	  return {
109	    ...readMethods,
110	
111	    async put(entry: T): Promise<void> {
112	      await core.doPut(ref, entry);
113	    },
114	
115	    async patch(id: string, fields: Partial<Omit<T, 'id'>>): Promise<T> {
116	      return (await core.doPatch(ref, id, fields as Record<string, unknown>)) as T;
117	    },
118	
119	    async delete(id: string): Promise<void> {
120	      await core.doDelete(ref, id);
121	    },
122	  };
123	}
124	
125	// ── Stacks core implementation ───────────────────────────────────────
126	
127	export class StacksCore {
128	  private readonly cdc = new CdcRegistry();
129	  private activeTx: ActiveTransaction | null = null;
130	
131	  /**
132	   * Phase-2 cross-transaction re-entry depth (D2). Mirrors the
133	   * `activeTx` instance-field pattern — single-flight per apparatus
134	   * instance, no AsyncLocalStorage. Incremented when entering a
135	   * `firePhase2` invocation and decremented on exit; gate-checked at
136	   * the next `runTransaction` entry so a runaway Phase-2 self-write
137	   * chain fails loud rather than pinning the CPU. See `runTransaction`
138	   * for the gate check (D6) and the firePhase2 wrapper (D5).
139	   */
140	  private phase2Depth = 0;
141	
142	  constructor(readonly backend: StacksBackend) {}
143	
144	  /**
145	   * Seal the CDC registry. After this is called, any further `watch()`
146	   * calls throw. Invoked by the guild runtime (arbor) via the
147	   * `phase:started` event, after all apparatus start() methods complete,
148	   * so startup-time writes in one apparatus don't lock out watcher
149	   * registration in a dependent apparatus that starts later.
150	   */
151	  sealCdc(): void {
152	    this.cdc.lock();
153	  }
154	
155	  // ── API surface ───────────────────────────────────────────────────
156	
157	  createApi(): StacksApi {
158	    const self = this;
159	
160	    return {
161	      book<T extends BookEntry>(ownerId: string, name: string): Book<T> {
162	        return createBookHandle<T>({ ownerId, book: name }, self, true);
163	      },
164	
165	      readBook<T extends BookEntry>(ownerId: string, name: string): ReadOnlyBook<T> {
166	        return createBookHandle<T>({ ownerId, book: name }, self, false) as ReadOnlyBook<T>;
167	      },
168	
169	      watch<T extends BookEntry>(
170	        ownerId: string,
171	        bookName: string,
172	        handler: ChangeHandler<T>,
173	        options?: WatchOptions,
174	      ): void {
175	        self.cdc.watch(
176	          ownerId,
177	          bookName,
178	          handler as ChangeHandler,
179	          options,
180	        );
181	      },
182	
183	      async transaction<R>(fn: (tx: TransactionContext) => Promise<R>): Promise<R> {
184	        return self.runTransaction(fn);
185	      },
186	
187	      async dropBook(ownerId: string, bookName: string): Promise<void> {
188	        return self.doDropBook(ownerId, bookName);
189	      },
190	    };
191	  }
192	
193	  // ── Transaction management ────────────────────────────────────────
194	
195	  async runTransaction<R>(fn: (tx: TransactionContext) => Promise<R>): Promise<R> {
196	    // If already in a transaction, just run (no nesting — flattened)
197	    if (this.activeTx) {
198	      const txCtx = this.createTransactionContext();
199	      return fn(txCtx);
200	    }
201	
202	    // Phase-2 cross-transaction re-entry bound (gate-entry, D5/D6).
203	    // If we're being entered from within a Phase-2 handler chain that
204	    // has already accumulated MAX_PHASE2_REENTRY_DEPTH hops, refuse to
205	    // open a new backend transaction so the offending handler write is
206	    // rejected (D10 partial-commit) and the chain terminates loud.
207	    // The throw fires before the try/catch below so the existing
208	    // rollback path — which only handles tx-level failures — is not
209	    // engaged for a transaction that was never opened.
210	    if (this.phase2Depth >= MAX_PHASE2_REENTRY_DEPTH) {
211	      throw new Phase2DepthExceededError(MAX_PHASE2_REENTRY_DEPTH);
212	    }
213	
214	    // Create new transaction
215	    const backendTx = this.backend.beginTransaction();
216	    const eventBuffer: BufferedEvent[] = [];
217	    this.activeTx = { backendTx, eventBuffer, depth: 0 };
218	
219	    try {
220	      const txCtx = this.createTransactionContext();
221	      const result = await fn(txCtx);
222	
223	      backendTx.commit();
224	      const coalesced = coalesceEvents(eventBuffer);
225	      this.activeTx = null;
226	
227	      // Fire Phase 2 handlers (after commit). Wrap with depth tracking
228	      // so the substrate-level cross-transaction re-entry bound (D5)
229	      // sees the correct hop count when a handler triggers another
230	      // Phase-2 chain. The increment must happen even though the gate
231	      // check fires in the *next* runTransaction call — that next call
232	      // reads `phase2Depth` to decide whether to refuse the write.
233	      this.phase2Depth++;
234	      try {
235	        await this.cdc.firePhase2(coalesced);
236	      } finally {
237	        this.phase2Depth--;
238	      }
239	
240	      return result;
241	    } catch (err) {
242	      try { backendTx.rollback(); } catch { /* already rolled back */ }
243	      this.activeTx = null;
244	      throw err;
245	    }
246	  }
247	
248	  private createTransactionContext(): TransactionContext {
249	    const self = this;
250	    return {
251	      book<T extends BookEntry>(ownerId: string, name: string): Book<T> {
252	        return createBookHandle<T>({ ownerId, book: name }, self, true);
253	      },
254	      readBook<T extends BookEntry>(ownerId: string, name: string): ReadOnlyBook<T> {
255	        return createBookHandle<T>({ ownerId, book: name }, self, false) as ReadOnlyBook<T>;
256	      },
257	    };
258	  }
259	
260	  // ── Write operations (called by book handles) ─────────────────────
261	
262	  async doPut(ref: BookRef, entry: BookEntry): Promise<void> {
263	    if (!this.activeTx) {
264	      return this.runTransaction(async () => this.doPutInTx(ref, entry));
265	    }
266	    return this.doPutInTx(ref, entry);
267	  }
268	
269	  private async doPutInTx(ref: BookRef, entry: BookEntry): Promise<void> {
270	    const tx = this.requireTx();
271	
272	    // Check cascade depth
273	    tx.depth++;
274	    if (tx.depth > MAX_CASCADE_DEPTH) {
275	      throw new Error(
276	        `[stacks] Maximum cascade depth (${MAX_CASCADE_DEPTH}) exceeded. ` +
277	        `This usually means a CDC handler is triggering itself recursively.`,
278	      );
279	    }
280	
281	    const needPrev = this.cdc.hasWatchers(ref.ownerId, ref.book);
282	    const result = tx.backendTx.put(ref, entry, { withPrev: needPrev });
283	
284	    const event: BufferedEvent = {
285	      ref: `${ref.ownerId}/${ref.book}`,
286	      ownerId: ref.ownerId,
287	      book: ref.book,
288	      docId: entry.id,
289	      type: result.created ? 'create' : 'update',
290	      entry,
291	      prev: result.prev,
292	    };
293	    tx.eventBuffer.push(event);
294	
295	    // Fire Phase 1 handlers (inside the transaction)
296	    if (result.created) {
297	      await this.cdc.firePhase1(ref.ownerId, ref.book, {
298	        type: 'create', ownerId: ref.ownerId, book: ref.book, entry,
299	      });
300	    } else {
301	      await this.cdc.firePhase1(ref.ownerId, ref.book, {
302	        type: 'update', ownerId: ref.ownerId, book: ref.book, entry, prev: result.prev!,
303	      });
304	    }
305	
306	    tx.depth--;
307	  }
308	
309	  async doPatch(ref: BookRef, id: string, fields: Record<string, unknown>): Promise<BookEntry> {
310	    if (!this.activeTx) {
311	      let result!: BookEntry;
312	      await this.runTransaction(async () => {
313	        result = await this.doPatchInTx(ref, id, fields);
314	      });
315	      return result;
316	    }
317	    return this.doPatchInTx(ref, id, fields);
318	  }
319	
320	  private async doPatchInTx(
321	    ref: BookRef,
322	    id: string,
323	    fields: Record<string, unknown>,
324	  ): Promise<BookEntry> {
325	    const tx = this.requireTx();
326	
327	    tx.depth++;
328	    if (tx.depth > MAX_CASCADE_DEPTH) {
329	      throw new Error(
330	        `[stacks] Maximum cascade depth (${MAX_CASCADE_DEPTH}) exceeded.`,
331	      );
332	    }
333	
334	    const result = tx.backendTx.patch(ref, id, fields);
335	
336	    const event: BufferedEvent = {
337	      ref: `${ref.ownerId}/${ref.book}`,
338	      ownerId: ref.ownerId,
339	      book: ref.book,
340	      docId: id,
341	      type: 'update',
342	      entry: result.entry,
343	      prev: result.prev,
344	    };
345	    tx.eventBuffer.push(event);
346	
347	    await this.cdc.firePhase1(ref.ownerId, ref.book, {
348	      type: 'update', ownerId: ref.ownerId, book: ref.book,
349	      entry: result.entry, prev: result.prev,
350	    });
351	
352	    tx.depth--;
353	
354	    return result.entry;
355	  }
356	
357	  async doDelete(ref: BookRef, id: string): Promise<void> {
358	    if (!this.activeTx) {
359	      return this.runTransaction(async () => this.doDeleteInTx(ref, id));
360	    }
361	    return this.doDeleteInTx(ref, id);
362	  }
363	
364	  private async doDeleteInTx(ref: BookRef, id: string): Promise<void> {
365	    const tx = this.requireTx();
366	
367	    tx.depth++;
368	    if (tx.depth > MAX_CASCADE_DEPTH) {
369	      throw new Error(
370	        `[stacks] Maximum cascade depth (${MAX_CASCADE_DEPTH}) exceeded.`,
371	      );
372	    }
373	
374	    const needPrev = this.cdc.hasWatchers(ref.ownerId, ref.book);
375	    const result = tx.backendTx.delete(ref, id, { withPrev: needPrev });
376	
377	    if (!result.found) {
378	      tx.depth--;
379	      return; // Silent no-op
380	    }
381	
382	    const event: BufferedEvent = {
383	      ref: `${ref.ownerId}/${ref.book}`,
384	      ownerId: ref.ownerId,
385	      book: ref.book,
386	      docId: id,
387	      type: 'delete',
388	      prev: result.prev,
389	    };
390	    tx.eventBuffer.push(event);
391	
392	    await this.cdc.firePhase1(ref.ownerId, ref.book, {
393	      type: 'delete', ownerId: ref.ownerId, book: ref.book, id, prev: result.prev!,
394	    });
395	
396	    tx.depth--;
397	  }
398	
399	  // ── Book retirement ───────────────────────────────────────────────
400	
401	  /**
402	   * Imperative whole-book retirement (D1, D3, D5, D6).
403	   *
404	   * Drops the backend storage for the book and, on success, fires a
405	   * single Phase-2 `delete-book` CDC event (D3, D9). Refuses to run
406	   * inside an active transaction (D6) — DDL is hard-separated from DML
407	   * by the substrate.
408	   *
409	   * Idempotent: a missing book is a silent no-op (D2). Watchers
410	   * registered for the dropped book are not unregistered (D14); they
411	   * remain in the registry but become dormant because no future writes
412	   * can fire them.
413	   */
414	  async doDropBook(ownerId: string, bookName: string): Promise<void> {
415	    if (this.activeTx) {
416	      throw new Error(
417	        `[stacks] dropBook("${ownerId}", "${bookName}") refused: a transaction is active. ` +
418	        `Book-drop is DDL and cannot participate in DML transactions — ` +
419	        `move the dropBook call outside transaction(...).`,
420	      );
421	    }
422	
423	    await this.backend.dropBook({ ownerId, book: bookName });
424	
425	    // Phase-2 only (D5): a book-drop is irreversible from the caller's
426	    // perspective, so a Phase-1 handler couldn't meaningfully roll it
427	    // back. Wrap in the same depth tracking as transactional Phase-2
428	    // delivery so a `delete-book` handler that opens a transaction
429	    // observes the same cross-transaction re-entry bound.
430	    this.phase2Depth++;
431	    try {
432	      await this.cdc.firePhase2([
433	        { type: 'delete-book', ownerId, book: bookName },
434	      ]);
435	    } finally {
436	      this.phase2Depth--;
437	    }
438	  }
439	
440	  // ── Read operations ───────────────────────────────────────────────
441	
442	  doGet(ref: BookRef, id: string): BookEntry | null {
443	    if (this.activeTx) {
444	      return this.activeTx.backendTx.get(ref, id);
445	    }
446	    // Outside a transaction — use a throwaway read transaction
447	    const tx = this.backend.beginTransaction();
448	    try {
449	      const result = tx.get(ref, id);
450	      tx.commit();
451	      return result;
452	    } catch (err) {
453	      tx.rollback();
454	      throw err;
455	    }
456	  }
457	
458	  async doFind(ref: BookRef, query: BookQuery): Promise<BookEntry[]> {
459	    // Handle OR queries at the apparatus level
460	    if (query.where && !Array.isArray(query.where) && 'or' in query.where) {
461	      return this.doFindOr(ref, query);
462	    }
463	
464	    const internal = translateQuery(query as BookQuery & { where?: WhereClause });
465	    if (this.activeTx) {
466	      return this.activeTx.backendTx.find(ref, internal);
467	    }
468	    const tx = this.backend.beginTransaction();
469	    try {
470	      const result = tx.find(ref, internal);
471	      tx.commit();
472	      return result;
473	    } catch (err) {
474	      tx.rollback();
475	      throw err;
476	    }
477	  }
478	
479	  /**
480	   * OR queries: run each branch as a separate backend query, deduplicate
481	   * by id, re-sort, and paginate the merged result set.
482	   *
483	   * V1 trade-off: when called outside an active transaction, each branch
484	   * opens its own throwaway read transaction. For synchronous backends
485	   * like better-sqlite3, the data can't change between branches so this
486	   * is safe. A hypothetical async backend could see different snapshots
487	   * per branch, producing inconsistent results — a known limitation
488	   * documented in the spec's implementation notes.
489	   *
490	   * Performance note: each branch is a separate backend query. count()
491	   * with OR cannot use the backend's efficient count path since
492	   * deduplication requires knowing which IDs overlap. Acceptable for v1.
493	   */
494	  private async doFindOr(ref: BookRef, query: BookQuery): Promise<BookEntry[]> {
495	    const orClauses = (query.where as { or: WhereClause[] }).or;
496	
497	    if (orClauses.length === 0) return [];
498	
499	    const seen = new Set<string>();
500	    const merged: BookEntry[] = [];
501	
502	    const runBranch = (branch: WhereClause): BookEntry[] => {
503	      const branchQuery = translateQuery({ where: branch } as BookQuery & { where?: WhereClause });
504	      if (this.activeTx) {
505	        return this.activeTx.backendTx.find(ref, branchQuery);
506	      }
507	      const tx = this.backend.beginTransaction();
508	      try {
509	        const result = tx.find(ref, branchQuery);
510	        tx.commit();
511	        return result;
512	      } catch (err) {
513	        tx.rollback();
514	        throw err;
515	      }
516	    };
517	
518	    for (const branch of orClauses) {
519	      const results = runBranch(branch);
520	      for (const entry of results) {
521	        if (!seen.has(entry.id)) {
522	          seen.add(entry.id);
523	          merged.push(entry);
524	        }
525	      }
526	    }
527	
528	    // Apply sorting
529	    if (query.orderBy) {
530	      const orderEntries = normalizeOrderBy(query.orderBy);
531	      merged.sort((a, b) => compareByOrderEntries(a, b, orderEntries));
532	    }
533	
534	    // Apply pagination
535	    let result = merged;
536	    if (query.offset !== undefined) {
537	      result = result.slice(query.offset);
538	    }
539	    if (query.limit !== undefined) {
540	      result = result.slice(0, query.limit);
541	    }
542	
543	    return result;
544	  }
545	
546	  async doCount(ref: BookRef, where?: WhereClause | { or: WhereClause[] }): Promise<number> {
547	    // Handle OR queries — must deduplicate, so use doFindOr
548	    if (where && !Array.isArray(where) && 'or' in where) {
549	      const results = await this.doFindOr(ref, { where } as BookQuery);
550	      return results.length;
551	    }
552	
553	    const internal = translateWhereClause(where as WhereClause | undefined);
554	    if (this.activeTx) {
555	      return this.activeTx.backendTx.count(ref, internal);
556	    }
557	    const tx = this.backend.beginTransaction();
558	    try {
559	      const result = tx.count(ref, internal);
560	      tx.commit();
561	      return result;
562	    } catch (err) {
563	      tx.rollback();
564	      throw err;
565	    }
566	  }
567	
568	  private requireTx(): ActiveTransaction {
569	    if (!this.activeTx) {
570	      throw new Error('[stacks] Write operation outside transaction — this is a bug');
571	    }
572	    return this.activeTx;
573	  }
574	}
