1	/**
2	 * CDC registry — handler registration, event buffering, and coalescing.
3	 *
4	 * Two-phase execution model:
5	 * - Phase 1 (failOnError: true):  runs INSIDE the transaction
6	 * - Phase 2 (failOnError: false): runs AFTER commit with coalesced events
7	 *
8	 * See: docs/specification.md (stacks § CDC)
9	 */
10	
11	import type { BookEntry, ChangeEvent, ChangeHandler, WatchOptions } from './types.ts';
12	
13	// ── Phase-2 re-entry depth error ──────────────────────────────────────
14	
15	/**
16	 * Thrown when the substrate-level Phase-2 cross-transaction re-entry
17	 * depth bound trips. Distinct from the Phase-1 cascade-depth error so
18	 * log filtering and the conformance regex can route operators to the
19	 * correct remediation path (D8): break a Phase-2 cycle by writing to a
20	 * non-watched book, or add a state-machine guard so the handler stops
21	 * calling itself.
22	 *
23	 * Re-thrown by `firePhase2`'s per-handler catch (rather than swallowed
24	 * with the usual handler-error log) so the bound surfaces past the
25	 * registry's catch-and-log block to the original `runTransaction`
26	 * caller (D6).
27	 */
28	export class Phase2DepthExceededError extends Error {
29	  constructor(limit: number) {
30	    super(
31	      `[stacks] Maximum Phase-2 re-entry depth (${limit}) exceeded. ` +
32	      `A Phase-2 handler chain re-entered Phase-2 across transaction ` +
33	      `boundaries past the substrate bound. Break the cycle by writing ` +
34	      `to a non-watched book, or add an in-handler state-machine guard ` +
35	      `so the handler stops calling itself.`,
36	    );
37	    this.name = 'Phase2DepthExceededError';
38	  }
39	}
40	
41	// ── Registry entry ────────────────────────────────────────────────────
42	
43	interface WatcherEntry {
44	  handler: ChangeHandler;
45	  failOnError: boolean;
46	}
47	
48	// ── Event buffer entry (raw, pre-coalesce) ────────────────────────────
49	
50	export interface BufferedEvent {
51	  ref: string;          // "${ownerId}/${bookName}"
52	  ownerId: string;
53	  book: string;
54	  docId: string;
55	  type: 'create' | 'update' | 'delete';
56	  entry?: BookEntry;    // present for create/update
57	  prev?: BookEntry;     // present for update/delete
58	}
59	
60	// ── Coalescing state machine ──────────────────────────────────────────
61	
62	interface CoalesceState {
63	  ownerId: string;
64	  book: string;
65	  docId: string;
66	  /** The first event's type — needed for coalescing rules. */
67	  firstType: 'create' | 'update' | 'delete';
68	  /** The most recent event's type. */
69	  lastType: 'create' | 'update' | 'delete';
70	  /** Pre-transaction state (prev from first event). */
71	  prev?: BookEntry;
72	  /** Final state (entry from last event). */
73	  entry?: BookEntry;
74	}
75	
76	/**
77	 * Coalesce buffered events per-document.
78	 *
79	 * Rules:
80	 *   create                    → create (final state)
81	 *   create → update(s)        → create (final state)
82	 *   create → delete           → (no event)
83	 *   update(s)                 → update (first prev, final state)
84	 *   update(s) → delete        → delete (first prev)
85	 *   delete                    → delete (prev)
86	 */
87	export function coalesceEvents(buffer: BufferedEvent[]): ChangeEvent<BookEntry>[] {
88	  const states = new Map<string, CoalesceState>();
89	
90	  for (const event of buffer) {
91	    const key = `${event.ref}:${event.docId}`;
92	    const existing = states.get(key);
93	
94	    if (!existing) {
95	      states.set(key, {
96	        ownerId: event.ownerId,
97	        book: event.book,
98	        docId: event.docId,
99	        firstType: event.type,
100	        lastType: event.type,
101	        prev: event.prev,
102	        entry: event.entry,
103	      });
104	    } else {
105	      existing.lastType = event.type;
106	      if (event.entry) existing.entry = event.entry;
107	      // prev stays as the first event's prev (pre-transaction state)
108	    }
109	  }
110	
111	  const events: ChangeEvent<BookEntry>[] = [];
112	
113	  for (const state of states.values()) {
114	    if (state.firstType === 'create' && state.lastType === 'delete') {
115	      // create → delete: no event (document never existed from observer's perspective)
116	      continue;
117	    }
118	
119	    if (state.firstType === 'create') {
120	      // create (possibly followed by updates): coalesces to create with final state
121	      events.push({
122	        type: 'create',
123	        ownerId: state.ownerId,
124	        book: state.book,
125	        entry: state.entry!,
126	      });
127	    } else if (state.lastType === 'delete') {
128	      // update(s) → delete: coalesces to delete with original prev
129	      events.push({
130	        type: 'delete',
131	        ownerId: state.ownerId,
132	        book: state.book,
133	        id: state.docId,
134	        prev: state.prev!,
135	      });
136	    } else {
137	      // update(s): coalesces to single update with first prev, final entry
138	      events.push({
139	        type: 'update',
140	        ownerId: state.ownerId,
141	        book: state.book,
142	        entry: state.entry!,
143	        prev: state.prev!,
144	      });
145	    }
146	  }
147	
148	  return events;
149	}
150	
151	// ── CDC Registry ──────────────────────────────────────────────────────
152	
153	export class CdcRegistry {
154	  private readonly watchers = new Map<string, WatcherEntry[]>();
155	  private locked = false;
156	
157	  /**
158	   * Register a CDC handler for a book.
159	   * Must be called during guild startup — arbor calls `sealCdc()` on the
160	   * Stacks core via the `phase:started` event after all apparatus start()
161	   * methods return, after which this throws.
162	   */
163	  watch(
164	    ownerId: string,
165	    bookName: string,
166	    handler: ChangeHandler,
167	    options?: WatchOptions,
168	  ): void {
169	    if (this.locked) {
170	      throw new Error(
171	        `[stacks] watch() called after guild startup completed. ` +
172	        `Handlers must be registered during apparatus startup.`,
173	      );
174	    }
175	
176	    const key = `${ownerId}/${bookName}`;
177	    let entries = this.watchers.get(key);
178	    if (!entries) {
179	      entries = [];
180	      this.watchers.set(key, entries);
181	    }
182	    entries.push({
183	      handler,
184	      failOnError: options?.failOnError ?? true,
185	    });
186	  }
187	
188	  /** Seal the CDC registry — called by the Stacks core when arbor fires phase:started, after all apparatus start() methods complete. */
189	  lock(): void {
190	    this.locked = true;
191	  }
192	
193	  /** Check if any handlers are registered for a book (controls pre-read). */
194	  hasWatchers(ownerId: string, bookName: string): boolean {
195	    const key = `${ownerId}/${bookName}`;
196	    const entries = this.watchers.get(key);
197	    return entries !== undefined && entries.length > 0;
198	  }
199	
200	  /** Get Phase 1 handlers (failOnError: true) for a book. */
201	  getPhase1Handlers(ownerId: string, bookName: string): WatcherEntry[] {
202	    const key = `${ownerId}/${bookName}`;
203	    return (this.watchers.get(key) ?? []).filter((e) => e.failOnError);
204	  }
205	
206	  /** Get Phase 2 handlers (failOnError: false) for a book. */
207	  getPhase2Handlers(ownerId: string, bookName: string): WatcherEntry[] {
208	    const key = `${ownerId}/${bookName}`;
209	    return (this.watchers.get(key) ?? []).filter((e) => !e.failOnError);
210	  }
211	
212	  /**
213	   * Fire Phase 1 handlers for a single event. Throws on handler error
214	   * (caller is responsible for rolling back the transaction).
215	   */
216	  async firePhase1(
217	    ownerId: string,
218	    bookName: string,
219	    event: ChangeEvent<BookEntry>,
220	  ): Promise<void> {
221	    for (const entry of this.getPhase1Handlers(ownerId, bookName)) {
222	      await entry.handler(event);
223	    }
224	  }
225	
226	  /**
227	   * Fire Phase 2 handlers for coalesced events. Errors are logged, not
228	   * thrown — except for `Phase2DepthExceededError`, which is re-thrown
229	   * so the substrate-level cross-transaction re-entry bound surfaces
230	   * past this catch-and-log block to the original `runTransaction`
231	   * caller (D6). Callers should wrap this invocation with depth
232	   * tracking (`enterPhase2Hop` / `exitPhase2Hop` on `StacksCore`); the
233	   * gate check itself fires inside `runTransaction` before any backend
234	   * transaction is opened.
235	   */
236	  async firePhase2(events: ChangeEvent<BookEntry>[]): Promise<void> {
237	    for (const event of events) {
238	      for (const entry of this.getPhase2Handlers(event.ownerId, event.book)) {
239	        try {
240	          await entry.handler(event);
241	        } catch (err) {
242	          // Phase-2 re-entry bound: surface past the per-handler catch
243	          // so the original runTransaction caller sees the failure
244	          // rather than having it swallowed and logged like a normal
245	          // handler error.
246	          if (err instanceof Phase2DepthExceededError) {
247	            throw err;
248	          }
249	          const msg = err instanceof Error ? err.message : String(err);
250	          console.warn(`[stacks] Phase 2 handler error (${event.ownerId}/${event.book}): ${msg}`);
251	        }
252	      }
253	    }
254	  }
255	}
